<script setup lang="ts">import type { ApprovalPolicyVisualDocument } from '#/api/system/bpm/policy'; import { ElCheckbox,ElCheckboxGroup,ElFormItem,ElInputNumber,ElOption,ElSelect } from 'element-plus'; const model=defineModel<ApprovalPolicyVisualDocument>({required:true});</script>
<template><ElFormItem label="通过方式"><ElSelect v-model="model.completionMode"><ElOption label="单人审批" value="SINGLE"/><ElOption label="依次审批" value="SEQUENTIAL"/><ElOption label="全部通过" value="ALL"/><ElOption label="任意一人通过" value="ANY"/><ElOption label="达到指定比例" value="RATIO"/></ElSelect></ElFormItem><ElFormItem v-if="model.completionMode==='RATIO'" label="通过比例"><ElInputNumber v-model="model.ratioPercent" :min="1" :max="100"/> %</ElFormItem><ElFormItem label="拒绝方式"><ElSelect v-model="model.rejectionRule"><ElOption label="任一拒绝立即结束" value="IMMEDIATE"/><ElOption label="无法达到通过条件时结束" value="WHEN_APPROVAL_UNREACHABLE"/></ElSelect></ElFormItem><ElFormItem label="允许动作"><ElCheckboxGroup v-model="model.allowedActions"><ElCheckbox value="APPROVE">通过</ElCheckbox><ElCheckbox value="REJECT">拒绝</ElCheckbox><ElCheckbox value="RETURN">退回</ElCheckbox></ElCheckboxGroup></ElFormItem></template>
